import React, { useRef, useState, useEffect } from 'react';
import { useNavigate, Link, useLocation } from 'react-router-dom';

const Header = ({ userInfo }) => {
  const navigate = useNavigate();
  const location = useLocation();

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('userInfo');
    navigate('/login');
  };

  // Helper to check if a path is active
  const isActive = (path) => location.pathname === path;

  // Common nav link style
  const navLinkBase = {
    textDecoration: 'none',
    color: '#0078d4',
    fontSize: '0.95rem',
    fontWeight: 600,
    display: 'flex',
    alignItems: 'center',
    padding: '8px 16px',
    borderRadius: '20px',
    transition: 'all 0.3s',
    background: 'linear-gradient(90deg, #e3f0ff 0%, #f7fafd 100%)',
    marginRight: '10px',
    boxShadow: '0 2px 8px #0078d411',
    border: '1px solid #e0e6ed',
  };
  const navLinkActive = {
    background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)',
    color: '#fff',
    boxShadow: '0 2px 8px #d6000044',
    border: '1.5px solid #0078d4',
  };

  // Dropdown state for profile menu
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const dropdownRef = useRef(null);

  // Close dropdown on outside click
  useEffect(() => {
    if (!dropdownOpen) return;
    function handleClick(e) {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setDropdownOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, [dropdownOpen]);

  // Keyboard accessibility (ESC to close)
  useEffect(() => {
    if (!dropdownOpen) return;
    function handleKey(e) {
      if (e.key === 'Escape') setDropdownOpen(false);
    }
    document.addEventListener('keydown', handleKey);
    return () => document.removeEventListener('keydown', handleKey);
  }, [dropdownOpen]);

  return (
    <header style={{
      background: 'linear-gradient(90deg, #f7fafd 0%, #e3f0ff 60%, #0078d4 90%, #d60000 100%)',
      boxShadow: '0 2px 10px rgba(0, 120, 212, 0.07)',
      borderBottom: '1.5px solid #e0e6ed',
      fontFamily: 'Poppins, Inter, sans-serif',
      fontWeight: 500,
      letterSpacing: 0.1,
      zIndex: 100,
      padding: '1.2rem 2.2rem'
    }}>
      <div className="container-fluid">
        <div className="d-flex justify-content-between align-items-center">
          <div className="d-flex align-items-center">
            <Link to="/dashboard">
              <img 
                src="/Logo/Sparkle RFID svg.svg" 
                alt="Sparkle RFID" 
                style={{ 
                  height: '48px',
                  marginRight: '30px'
                }} 
              />
            </Link>
            <nav className="d-flex align-items-center">
              <Link 
                to="/dashboard"
                style={{
                  ...navLinkBase,
                  ...(isActive('/dashboard') ? navLinkActive : {}),
                }}
                onMouseOver={e => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                  e.currentTarget.style.color = '#fff';
                  const icon = e.currentTarget.querySelector('i');
                  if (icon) icon.style.color = '#fff';
                }}
                onMouseOut={e => {
                  if (isActive('/dashboard')) {
                    e.currentTarget.style.background = navLinkActive.background;
                    e.currentTarget.style.color = navLinkActive.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#fff';
                  } else {
                    e.currentTarget.style.background = navLinkBase.background;
                    e.currentTarget.style.color = navLinkBase.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#0078d4';
                  }
                }}
              >
                <i className="fas fa-home me-2" style={{ color: isActive('/dashboard') ? '#fff' : '#0078d4' }}></i>
                Home
              </Link>
              <Link 
                to="/rfid-integration"
                style={{
                  ...navLinkBase,
                  marginLeft: '10px',
                  ...(isActive('/rfid-integration') ? navLinkActive : {}),
                }}
                onMouseOver={e => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                  e.currentTarget.style.color = '#fff';
                  const icon = e.currentTarget.querySelector('i');
                  if (icon) icon.style.color = '#fff';
                }}
                onMouseOut={e => {
                  if (isActive('/rfid-integration')) {
                    e.currentTarget.style.background = navLinkActive.background;
                    e.currentTarget.style.color = navLinkActive.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#fff';
                  } else {
                    e.currentTarget.style.background = navLinkBase.background;
                    e.currentTarget.style.color = navLinkBase.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#0078d4';
                  }
                }}
              >
                <i className="fas fa-plug me-2" style={{ color: isActive('/rfid-integration') ? '#fff' : '#0078d4' }}></i>
                RFID Integration
              </Link>
              <Link 
                to="/inventory"
                style={{
                  ...navLinkBase,
                  marginLeft: '10px',
                  ...(isActive('/inventory') ? navLinkActive : {}),
                }}
                onMouseOver={e => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                  e.currentTarget.style.color = '#fff';
                  const icon = e.currentTarget.querySelector('i');
                  if (icon) icon.style.color = '#fff';
                }}
                onMouseOut={e => {
                  if (isActive('/inventory')) {
                    e.currentTarget.style.background = navLinkActive.background;
                    e.currentTarget.style.color = navLinkActive.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#fff';
                  } else {
                    e.currentTarget.style.background = navLinkBase.background;
                    e.currentTarget.style.color = navLinkBase.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#0078d4';
                  }
                }}
              >
                <i className="fas fa-box me-2" style={{ color: isActive('/inventory') ? '#fff' : '#0078d4' }}></i>
                Inventory
              </Link>
              <Link 
                to="/upload-rfid"
                style={{
                  ...navLinkBase,
                  marginLeft: '10px',
                  ...(isActive('/upload-rfid') ? navLinkActive : {}),
                }}
                onMouseOver={e => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                  e.currentTarget.style.color = '#fff';
                  const icon = e.currentTarget.querySelector('i');
                  if (icon) icon.style.color = '#fff';
                }}
                onMouseOut={e => {
                  if (isActive('/upload-rfid')) {
                    e.currentTarget.style.background = navLinkActive.background;
                    e.currentTarget.style.color = navLinkActive.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#fff';
                  } else {
                    e.currentTarget.style.background = navLinkBase.background;
                    e.currentTarget.style.color = navLinkBase.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#0078d4';
                  }
                }}
              >
                <i className="fas fa-upload me-2" style={{ color: isActive('/upload-rfid') ? '#fff' : '#0078d4' }}></i>
                Upload EPC Data
              </Link>
            </nav>
          </div>
          {userInfo && (
            <div className="d-flex align-items-center" style={{ position: 'relative' }}>
              {/* Profile button */}
              <button
                className="profile-btn"
                style={{
                  background: 'linear-gradient(90deg, #e3f0ff 0%, #0078d4 100%)',
                  padding: '8px 18px 8px 14px',
                  borderRadius: '22px',
                  display: 'flex',
                  alignItems: 'center',
                  fontFamily: 'Poppins, Inter, sans-serif',
                  fontWeight: 600,
                  boxShadow: '0 2px 8px #0078d411',
                  border: '1px solid #e0e6ed',
                  color: '#222',
                  fontSize: '1.05rem',
                  cursor: 'pointer',
                  outline: 'none',
                  transition: 'box-shadow 0.2s',
                  position: 'relative',
                  zIndex: 11,
                }}
                onClick={() => setDropdownOpen((v) => !v)}
                aria-haspopup="true"
                aria-expanded={dropdownOpen}
                tabIndex={0}
              >
                <i className="fas fa-user-circle me-2" style={{ color: '#0078d4', fontSize: 22 }}></i>
                <span style={{ fontWeight: 600, color: '#222', fontFamily: 'Poppins, Inter, sans-serif', fontSize: '1.05rem' }}>
                  {userInfo.Username}
                </span>
                <i className={`fas fa-chevron-${dropdownOpen ? 'up' : 'down'} ms-2`} style={{ color: '#0078d4', fontSize: 14, marginLeft: 8 }}></i>
              </button>
              {/* Dropdown menu */}
              {dropdownOpen && (
                <div
                  ref={dropdownRef}
                  className="profile-dropdown"
                  style={{
                    position: 'absolute',
                    top: 'calc(100% + 8px)',
                    right: 0,
                    minWidth: 210,
                    background: 'linear-gradient(120deg, #e3f0ff 0%, #0078d4 60%, #d60000 100%)',
                    borderRadius: 18,
                    boxShadow: '0 8px 32px rgba(0,0,0,0.13)',
                    padding: '14px 0 8px 0',
                    zIndex: 100,
                    border: '1.5px solid #e0e6ed',
                    animation: 'fadeInDown 0.18s',
                  }}
                  tabIndex={-1}
                >
                  <div style={{ padding: '8px 22px 10px 22px', display: 'flex', alignItems: 'center', gap: 10 }}>
                    <i className="fas fa-id-badge" style={{ color: '#fff', fontSize: 17, background: 'rgba(0,120,212,0.7)', borderRadius: '50%', padding: 6 }}></i>
                    <span style={{ color: '#fff', fontWeight: 600, fontSize: 15, letterSpacing: 0.2 }}>Client Code:</span>
                    <span style={{ color: '#fff', fontWeight: 700, fontSize: 15 }}>{userInfo.ClientCode}</span>
                  </div>
                  <hr style={{ margin: '6px 0 8px 0', border: 0, borderTop: '1.5px solid #e0e6ed' }} />
                  <button
                    onClick={handleLogout}
                    style={{
                      background: 'none',
                      border: 'none',
                      color: '#fff',
                      fontWeight: 600,
                      fontFamily: 'Poppins, Inter, sans-serif',
                      fontSize: 15,
                      width: '100%',
                      textAlign: 'left',
                      padding: '10px 22px',
                      display: 'flex',
                      alignItems: 'center',
                      gap: 12,
                      cursor: 'pointer',
                      borderRadius: 12,
                      transition: 'background 0.18s',
                    }}
                    onMouseOver={e => { e.currentTarget.style.background = 'rgba(214,0,0,0.13)'; }}
                    onMouseOut={e => { e.currentTarget.style.background = 'none'; }}
                  >
                    <i className="fas fa-sign-out-alt" style={{ color: '#fff', fontSize: 17 }}></i>
                    Logout
                  </button>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </header>
  );
};

export default Header;
